@module masterMix  src=masterMix.lua  loc=140  sha=7c4c840  mode=chunk
@deps chrome, ctx

# Shapes
  @shape  masterMix = { segment = { id = 'master', render } }   -- one shared toolbar segment

# Imports
  @require ImGui = 'imgui'  @ 6
      @reaper  reads GetMasterTrack + D_VOL + Track_GetPeakInfo(0/1 peak, 1024 loudness) + time_precise; writes via CSurf_OnVolumeChange

# Private state
  @state colour = chrome.colour  @ 9
  @state WIDTH = 170  @ 11
  @state BAR_H = 8  @ 12
  @state HANDLE_W = 9  @ 13   -- grab handle width, px
  @state HANDLE_H = 13  @ 14   -- grab handle height, px
  @state METER_MIN = -60  @ 15
  @state METER_MAX = 6  @ 16
  @state ZERO_FRAC = (0 - METER_MIN) / (METER_MAX - METER_MIN)  @ 17   -- where 0 dB sits across the bar
  @state DETENT_DB = 0.7  @ 18   -- a drag snaps to unity within this band of 0 dB
  @state PEAK_SMOOTH = 0.5  @ 19   -- ~2-frame averaging on the bar fill (the raw peak is nervy)
  @state HOLD_TIME = 1.5  @ 20   -- seconds a peak is held before it releases to the current level
  @state suppressDrag = false  @ 68   -- a double-click reset holds off drag until the mouse releases
  @state peakL, peakR = 0, 0  @ 69   -- frame-averaged bar fills
  @state holdL, holdR = METER_MIN, METER_MIN  @ 70   -- held peak per channel, dB
  @state holdAtL, holdAtR = 0, 0  @ 71   -- time_precise() when each hold last latched

# Private functions
  @fn clamp01(v)  @ 22
  @fn px(v)  @ 23
  @fn ampToDb(a)  @ 24
  @fn dbFrac(db)  @ 25
  @fn loudnessDb(raw)  @ 29
      -- Channel 1024 returns loudness, but its scale is undocumented; treated as
      -- linear amplitude here. See docs/masterMix.md § Loudness scale.
  @fn volToFrac(vol)  @ 32-35
      -- REAPER's own fader taper (matches a track fader): frac 0..1 <-> dB <-> vol.
  @fn fracToDb(frac)  @ 36
  @fn dbToVol(db)  @ 37
  -- Crisp (non-AA) primitives: ReaImGui's AddLine/AddRect are anti-aliased with
  -- no per-call toggle, so axis-aligned filled rects stand in for 1px rules.
  @fn hrule(dl, x0, x1, y, col)  @ 42
  @fn vrule(dl, x, y0, y1, col)  @ 43
  @fn chip(dl, x, y0, y1, col)  @ 44
  @fn box(dl, x0, y0, x1, y1, col)  @ 45-48
  -- Meter bars
  @fn drawBar(dl, x, top, peak, holdDb, loudX)  @ 52-64
  -- Segment
  @fn holdPeak(heldDb, latchedAt, db, now)  @ 75-78
      -- Latch a higher peak and stamp the time; once HOLD_TIME elapses with nothing
      -- louder, release the hold to the current level.
  @fn render()  @ 80-138

# Uses (outbound edges)
  @use call    imgui.CalcTextSize  @ render:131
  @use call    imgui.DrawList_AddRectFilled  @ hrule:42 vrule:43 chip:44 drawBar:53,57,59 render:124,134
  @use call    imgui.DrawList_AddText  @ render:136
  @use call    imgui.GetCursorScreenPos  @ render:84
  @use call    imgui.GetForegroundDrawList  @ render:132
  @use call    imgui.GetFrameHeight  @ render:86
  @use call    imgui.GetMousePos  @ render:96
  @use call    imgui.GetWindowDrawList  @ render:87
  @use call    imgui.InvisibleButton  @ render:90
  @use call    imgui.IsItemActive  @ render:91
  @use call    imgui.IsItemHovered  @ render:92
  @use call    imgui.IsMouseDoubleClicked  @ render:92
  @use require imgui  @ 6

# REAPER API surface
  @reaper DB2SLIDER
  @reaper GetMasterTrack
  @reaper CSurf_OnVolumeChange
  @reaper Track_GetPeakInfo
  @reaper time_precise
  @reaper GetMediaTrackInfo_Value
